import { ResponseError } from '@backstage/errors';

type HttpInit = {
  headers?: Record<string, string>;
  method?: string;
  body?: any;
  signal?: AbortSignal;
};

export async function httpJson<T>(url: string, init?: HttpInit): Promise<T> {
  const res = await fetch(url, {
    ...init,
    body: init?.body ? JSON.stringify(init.body) : undefined,
    headers: {
      ...(init?.body ? { 'Content-Type': 'application/json' } : {}),
      ...init?.headers,
    },
  });
  if (!res.ok) {
    const responseError = await ResponseError.fromResponse(res);
    const causeMessage = responseError.cause?.message;
    throw new Error(
      causeMessage || `Request failed with ${res.status} ${res.statusText}`,
      { cause: responseError },
    );
  }
  return (await res.json()) as T;
}
